import { Component, OnInit, OnDestroy, ViewChild, ElementRef } from '@angular/core';
import { Router } from '@angular/router';
import { HttpClient } from '@angular/common/http';
import { AuthService } from '../../services/auth.service';

@Component({
  selector: 'app-candidate-dashboard',
  template: `
  <div class="page">
    <!-- hidden global file input used to pick signed-offer files so DOM re-renders don't clear selection -->
    <input #globalSignedInput type="file" accept=".pdf,application/pdf" style="display:none" (change)="onGlobalSignedSelected($event)" />
    <div class="page-header">
      <div>
        <h1 class="page-title">Candidate Dashboard</h1>
        <p class="muted" style="margin:0">{{auth.user?.email}}</p>
      </div>
      <button class="btn btn-black" (click)="logout()">Logout</button>
    </div>

    <h2>Available Internships</h2>
    <div class="card-grid">
      <div *ngFor="let i of internships" class="card-item">
        <h3 style="text-align:center;color:var(--text)">{{i.companyName}}</h3>
        <p><b>Role:</b> {{i.title}}</p>
        <p><b>Location:</b> {{i.workLocation}}</p>
        <p><b>CTC:</b> {{i.ctc}}</p>
        <p><b>Description:</b> {{i.description}}</p>
        <div class="card-actions">
          <button *ngIf="hasApplied(i.id); else canApply" disabled class="btn btn-ghost">Applied</button>
          <ng-template #canApply><button (click)="selectInternship(i)" class="btn">Apply</button></ng-template>
        </div>
      </div>
    </div>

    <div *ngIf="selectedInternship" class="card-item" style="margin-top:20px">
      <h2>Apply for {{selectedInternship.title}}</h2>
      <input class="form-control" placeholder="Full Name" [(ngModel)]="candidateName" />
      <input class="form-control" placeholder="Phone" [(ngModel)]="phone" />
      <input class="form-control" placeholder="Degree" [(ngModel)]="degree" />
      <input class="form-control" placeholder="College" [(ngModel)]="college" />
      <input class="form-control" placeholder="CGPA" [(ngModel)]="cgpa" />
      <input class="form-control" placeholder="Skills" [(ngModel)]="skills" />
      <input type="file" accept="application/pdf" (change)="onResumeSelected($event)" />
      <div class="card-actions">
        <button (click)="handleApply()" class="btn">Submit Application</button>
      </div>
    </div>

    <h2 style="margin-top:40px">My Applications</h2>
    <div class="card-grid">
      <div *ngFor="let app of applications" class="card-item">
        <h3 style="text-align:center;color:var(--text)">{{ getInternship(app)?.companyName }}</h3>
        <h3>{{ getInternship(app)?.title }}</h3>

      <div *ngIf="app.status === 'TEST_ACTIVE'">
        <p>Test active till {{ formatDate(app.testDate) }}</p>
        <button (click)="router.navigate(['/candidate/test', app.id])" class="btn">Take Test</button>
      </div>

      <div *ngIf="app.status === 'TEST_PASSED'"> <p style="color:#111827">Online Test-Passed</p> </div>
      <div *ngIf="app.status === 'TEST_FAILED'"> <p style="color:red;font-weight:bold">Online Test-Not Cleared</p> </div>

      <!-- L1 scheduled / result -->
      <div *ngIf="app.interviewStatus === 'L1_SCHEDULED'">
            <div style="margin-top:8px;padding:8px;border:1px solid var(--card-border);border-radius:6px">L1 Interview Scheduled<br/>
          <b>Date:</b> {{ formatDate(app.l1Date) }}<br/>
          <b>Time:</b> {{ formatTime(app.l1Time) }}<br/>
          <b>Mode:</b> {{ app.l1Mode }}<br/>
          <b>Interviewer:</b> {{ getInterviewerName(app.l1InterviewerId) }}
        </div>
      </div>
      <div *ngIf="app.l1Result === 'PASSED'"> <p style="color:#111827">L1 Interview - Cleared</p> </div>
      <div *ngIf="app.interviewStatus === 'L1_FAILED'"> <p style="color:red;font-weight:bold">L1 Interview - Not Cleared</p> </div>

      <!-- L2 scheduled / result -->
      <div *ngIf="app.interviewStatus === 'L2_SCHEDULED'">
        <div style="margin-top:8px;padding:8px;border:1px solid #e5e7eb;border-radius:6px">L2 Interview Scheduled<br/>
          <b>Date:</b> {{ formatDate(app.l2Date) }}<br/>
          <b>Time:</b> {{ formatTime(app.l2Time) }}<br/>
          <b>Mode:</b> {{ app.l2Mode }}<br/>
          <b>Interviewer:</b> {{ getInterviewerName(app.l2InterviewerId) }}
        </div>
      </div>
      <div *ngIf="app.l2Result === 'PASSED'"> <p style="color:#111827">L2 Interview - Cleared</p> </div>
      <div *ngIf="app.interviewStatus === 'L2_FAILED'"> <p style="color:red;font-weight:bold">L2 Interview - Not Cleared</p> </div>

      <!-- HR scheduled / result -->
      <div *ngIf="app.interviewStatus === 'HR_SCHEDULED'">
        <div style="margin-top:8px;padding:8px;border:1px solid #e5e7eb;border-radius:6px">HR Interview Scheduled<br/>
          <b>Date:</b> {{ formatDate(app.hrDate) }}<br/>
          <b>Time:</b> {{ formatTime(app.hrTime) }}<br/>
          <b>Mode:</b> {{ app.hrMode }}
        </div>
      </div>
      <div *ngIf="app.hrResult === 'PASSED'"> <p style="color:#111827">HR Round - Cleared</p> </div>
      <div *ngIf="app.hrResult === 'FAILED'"> <p style="color:red;font-weight:bold">HR Round - Not Cleared</p> </div>

      <div *ngIf="app.offerLetterFile && app.offerStatus !== 'REJECTED'">
        <a [href]="'http://localhost:8080/offers/' + app.offerLetterFile" target="_blank">Download Offer Letter</a>

        <div *ngIf="app.offerStatus === 'PENDING'">
          <button (click)="updateOfferStatus(app.id, 'ACCEPTED')">Accept</button>
          <button (click)="updateOfferStatus(app.id, 'REJECTED')">Reject</button>
        </div>

            <div *ngIf="app.offerStatus === 'ACCEPTED' && !app.signedOfferLetter">
              <button (click)="openSignedFilePicker(app.id)">Choose Signed Offer</button>
              <button (click)="uploadSignedOffer(app.id)" style="margin-left:8px">Upload Signed Offer</button>
              <span *ngIf="signedFiles[app.id]" style="margin-left:8px">Selected: {{ signedFiles[app.id].name }}</span>
            </div>

            <div *ngIf="app.signedOfferLetter">
          <ng-container *ngIf="employee">
            <div style="margin-top:15px;padding:15px;border-radius:8px;background:linear-gradient(180deg,#f8fffa,#ffffff);border:1px solid rgba(16,163,84,0.08)">
              <h3 style="color:var(--success)"> Welcome to the Company</h3>
              <p><b>Employee ID:</b> {{employee.employeeId}}</p>
              <p><b>Date of Joining:</b> {{employee.dateOfJoining}}</p>
              <p><b>Reporting Time:</b> {{employee.reportingTime}}</p>
              <p><b>Location:</b> {{employee.workLocation}}</p>
              <p><b>Manager:</b> {{employee.managerName}}</p>
              <p><b>Manager Email:</b> {{employee.managerEmail}}</p>
              <p><b>Manager Contact:</b> {{employee.managerContact}}</p>
            </div>
          </ng-container>

            <ng-container *ngIf="!employee">
            <p class="muted">Offer Process-Completed</p>
            <!-- If offer accepted and signed, allow candidate to fill onboarding inline -->
            <div *ngIf="app.signedOfferLetter && (!onboardingStatus || onboardingStatus==='REJECTED')">
              <div *ngIf="!candidateOnboardingForms[app.id]">
                <button class="btn" (click)="openOnboardingForm(app.id)">Fill Onboarding Form</button>
              </div>
              <div *ngIf="candidateOnboardingForms[app.id]" class="card-item" style="margin-top:8px;padding:12px;border-style:dashed">
                <label class="form-label">Address</label>
                <input class="form-control" [(ngModel)]="candidateOnboardingForms[app.id].address" />
                <label class="form-label">Aadhaar Number</label>
                <input class="form-control" [(ngModel)]="candidateOnboardingForms[app.id].aadhaar" />
                <label class="form-label">PAN Number</label>
                <input class="form-control" [(ngModel)]="candidateOnboardingForms[app.id].pan" />
                <label class="form-label">Bank Account</label>
                <input class="form-control" [(ngModel)]="candidateOnboardingForms[app.id].bankAccount" />
                <div class="card-actions">
                  <button class="btn" (click)="submitOnboarding(app.id)">Submit Onboarding</button>
                  <button class="btn btn-ghost" (click)="cancelOnboardingForm(app.id)">Cancel</button>
                </div>
              </div>
            </div>
            <p *ngIf="onboardingStatus==='PENDING'" style="color:orange;margin-top:10px">Onboarding submitted – waiting for HR verification</p>
            <p *ngIf="onboardingStatus==='VERIFIED'" style="color:var(--success);margin-top:10px">Onboarding verified</p>
            <p *ngIf="onboardingStatus==='REJECTED'" style="color:var(--danger);margin-top:10px">Onboarding rejected</p>
          </ng-container>
        </div>
      </div>
      </div>
    </div>
  </div>
  `
})
export class CandidateDashboardComponent implements OnInit, OnDestroy {
  internships: any[] = [];
  applications: any[] = [];
  selectedInternship: any = null;
  candidateName = '';
  phone = '';
  degree = '';
  college = '';
  cgpa = '';
  skills = '';
  resume: any = null;
  signedFiles: any = {};
  onboardingStatus: any = null;
  onboardingStatusMap: Record<string, any> = {};
  latestSignedOfferId: any = null;
  employee: any = null;
  candidateOnboardingForms: Record<string, any> = {};

  private intervalId: any;
  private pollingPaused = false;
  pickerAppId: any = null;
  @ViewChild('globalSignedInput') globalSignedInput!: ElementRef<HTMLInputElement>;

  constructor(public auth: AuthService, private http: HttpClient, public router: Router) {}

  ngOnInit() {
    if (!this.auth.user?.email) return;
    this.fetchInternships();
    this.fetchApplications();
    this.fetchEmployee();
    this.intervalId = setInterval(() => { if (!this.pollingPaused) { this.fetchApplications(); this.fetchOnboarding(); } }, 5000);
  }

  ngOnDestroy() { clearInterval(this.intervalId); }

  logout() { this.auth.logout(); this.router.navigate(['/']); }

  pausePolling() { this.pollingPaused = true; }

  resumePolling() { this.pollingPaused = false; }

  openSignedFilePicker(id: any) {
    this.pickerAppId = id;
    try { this.globalSignedInput.nativeElement.click(); } catch (err) { console.error('File picker open failed', err); }
  }

  onGlobalSignedSelected(e: any) {
    const file = e.target.files?.[0];
    if (!file) return;
    const isPdfMime = file.type && file.type.toLowerCase().includes('pdf');
    const isPdfExt = file.name && file.name.toLowerCase().endsWith('.pdf');
    if (!isPdfMime && !isPdfExt) { alert('Please select a PDF signed offer'); e.target.value = ''; return; }
    this.signedFiles = { ...this.signedFiles, [this.pickerAppId]: file };
    // clear the input so selecting same file again will fire change event next time
    e.target.value = '';
  }

  openOnboardingForm(appId: any) {
    const app = this.applications.find(a => a.id === appId);
    if (app && !app.signedOfferLetter) { return alert('Please upload the signed offer before filling onboarding'); }
    this.candidateOnboardingForms = { ...this.candidateOnboardingForms, [appId]: { address: '', aadhaar: '', pan: '', bankAccount: '' } };
    this.pausePolling();
  }

  cancelOnboardingForm(appId: any) {
    const copy = { ...this.candidateOnboardingForms };
    delete copy[appId];
    this.candidateOnboardingForms = copy;
    this.resumePolling();
  }

  async submitOnboarding(appId: any) {
    const payload = this.candidateOnboardingForms[appId];
    if (!payload) return;
    if (!payload.address || !payload.aadhaar || !payload.pan || !payload.bankAccount) return alert('Please fill all onboarding fields');
    try {
      await this.http.post('http://localhost:8080/api/onboarding', { ...payload, email: this.auth.user?.email, applicationId: appId }).toPromise();
      alert('Onboarding submitted successfully');
      // cleanup and refresh
      this.cancelOnboardingForm(appId);
      await this.fetchApplications();
      this.latestSignedOfferId = appId;
      await this.fetchOnboardingFor(appId);
    } catch (err) {
      console.error(err);
      alert('Error submitting onboarding');
    }
  }

  async fetchOnboarding() {
    // fetch onboarding for all signed applications
    const signedApps = this.applications.filter((a: any) => a.signedOfferLetter).map(a => a.id);
    await Promise.all(signedApps.map(id => this.fetchOnboardingFor(id)));
  }

  async fetchOnboardingFor(appId: any) {
    try {
      const res: any = await this.http.get(`http://localhost:8080/api/onboarding/application/${appId}`).toPromise();
      const status = res && res.length > 0 ? res[res.length - 1].status : null;
      this.onboardingStatusMap = { ...this.onboardingStatusMap, [appId]: status };
      return status;
    } catch (err) { console.error(err); this.onboardingStatusMap = { ...this.onboardingStatusMap, [appId]: null }; return null; }
  }

  getOnboardingStatus(app: any) {
    return this.onboardingStatusMap[app.id] || null;
  }

  async fetchEmployee() {
    if (!this.auth.user?.email) return;
    try { this.employee = await this.http.get(`http://localhost:8080/api/employees/${this.auth.user.email}`).toPromise(); } catch (err) { this.employee = null; }
  }

  async fetchInternships() { try { this.internships = await this.http.get<any[]>('http://localhost:8080/api/internships').toPromise(); } catch (err) { console.error(err); } }

  async fetchApplications() { try {
      const res: any = await this.http.get<any[]>('http://localhost:8080/api/applications').toPromise();
      const filtered = res.filter((app: any) => app.email === this.auth.user?.email);
      this.applications = filtered;
      const signed = filtered.filter((app: any) => app.signedOfferLetter).slice(-1)[0];
      this.latestSignedOfferId = signed?.id || null;
      this.fetchOnboarding();
    } catch (err) { console.error(err); }
  }

  hasApplied(internshipId: any) { return this.applications.some(app => app.internshipId === internshipId); }

  selectInternship(i: any) { this.selectedInternship = i; }

  onResumeSelected(e: any) { this.resume = e.target.files?.[0]; }

  async handleApply() {
    if (!this.resume) return alert('Please upload resume');
    const form = new FormData();
    form.append('internshipId', this.selectedInternship.id);
    form.append('candidateName', this.candidateName);
    form.append('email', this.auth.user?.email || '');
    form.append('phone', this.phone);
    form.append('degree', this.degree);
    form.append('college', this.college);
    form.append('cgpa', this.cgpa);
    form.append('skills', this.skills);
    form.append('resume', this.resume);
    await this.http.post('http://localhost:8080/api/applications/apply', form).toPromise();
    alert('Application submitted!');
    this.selectedInternship = null; this.candidateName = this.phone = this.degree = this.college = this.cgpa = this.skills = ''; this.resume = null; this.fetchApplications();
  }

  getInternship(app: any) { return this.internships.find(i => i.id === app.internshipId); }

  formatDate(dateString: any) { if (!dateString) return ''; return new Date(dateString).toLocaleDateString('en-GB', { day: '2-digit', month: 'short', year: 'numeric' }); }

  updateOfferStatus(id: any, status: string) { this.http.post('http://localhost:8080/api/applications/offer-status', null, { params: { applicationId: id, status } as any }).toPromise().then(() => this.fetchApplications()); }

  // legacy per-input handler (kept for compatibility but prefer global picker)
  onSignedOfferSelected(id: any, e: any) {
    const file = e.target.files?.[0];
    if (!file) return;
    const isPdfMime = file.type && file.type.toLowerCase().includes('pdf');
    const isPdfExt = file.name && file.name.toLowerCase().endsWith('.pdf');
    if (!isPdfMime && !isPdfExt) { alert('Please select a PDF signed offer'); return; }
    this.signedFiles = { ...this.signedFiles, [id]: file };
  }

  async uploadSignedOffer(id: any) {
    const file = this.signedFiles[id]; if (!file) return alert('Upload signed offer');
    this.pausePolling();
    const y = window.scrollY || 0;
    try {
      const form = new FormData(); form.append('applicationId', id); form.append('file', file);
      // attempt multiple endpoint patterns
      const endpoints = [
        `http://localhost:8080/api/applications/upload-signed-offer/${encodeURIComponent(id)}`,
        `http://localhost:8080/api/applications/upload-signed-offer?applicationId=${encodeURIComponent(id)}`,
        `http://localhost:8080/api/applications/upload-signed-offer`
      ];
      let uploaded = false;
      let lastErr: any = null;
      for (const url of endpoints) {
        try {
          await this.http.post(url, form, { responseType: 'text' }).toPromise();
          uploaded = true; break;
        } catch (err) { lastErr = err; }
      }
      if (!uploaded) { console.error('Signed offer upload failed', lastErr); alert('Error uploading signed offer'); throw lastErr; }
      alert('Signed offer uploaded');
      // update local state so UI can immediately allow onboarding
      this.applications = this.applications.map(a => a.id === id ? { ...a, signedOfferLetter: true } : a);
      this.latestSignedOfferId = id;
      this.signedFiles = { ...this.signedFiles, [id]: null };
      // refresh server state and onboarding status for this app
      try { await this.fetchApplications(); } catch (e) { /* ignore fetch errors */ }
      await this.fetchOnboardingFor(id);
      // Auto-open onboarding form for better UX
      this.openOnboardingForm(id);
    } finally {
      setTimeout(() => window.scrollTo(0, y), 0);
      this.resumePolling();
    }
  }

  // template now uses CSS classes; legacy style objects retained for compatibility but unused
  card = {} as any;
  input = {} as any;
  formBox = {} as any;
}
